namespace NotificationApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 6;
    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", new DateTime(2026, 5, 22, 8, 0, 0)),
        new(2, "Your profile was updated.", new DateTime(2026, 5, 22, 9, 15, 0)),
        new(3, "New comment on your post.", new DateTime(2026, 5, 22, 10, 30, 0)),
        new(4, "Server maintenance scheduled.", new DateTime(2026, 5, 22, 12, 0, 0)),
        new(5, "You have a new follower.", new DateTime(2026, 5, 22, 14, 45, 0)),
    ];

    private static readonly string[] SampleMessages =
    [
        "Deployment completed successfully.",
        "New user signed up.",
        "Disk usage above 80%.",
        "Backup finished.",
        "Payment received.",
        "API rate limit warning.",
        "Certificate expiring soon.",
        "New support ticket opened.",
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>
    /// Returns notifications added after the given ID, simulating new activity.
    /// Randomly generates a new notification ~50% of the time.
    /// </summary>
    public Task<List<Notification>> GetNewNotificationsSinceAsync(int lastId)
    {
        if (Random.Shared.Next(2) == 0)
        {
            lock (_notifications)
            {
                var message = SampleMessages[Random.Shared.Next(SampleMessages.Length)];
                _notifications.Add(new(_nextId++, message, DateTime.Now));
            }
        }

        lock (_notifications)
        {
            return Task.FromResult(_notifications.Where(n => n.Id > lastId).ToList());
        }
    }
}

