@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationApp.Services.Notification>? notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we don't re-fetch data that was persisted from prerender
        notifications ??= await NotificationSvc.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender never runs during prerender — only when interactive
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var lastId = notifications?.Count > 0
                    ? notifications.Max(n => n.Id)
                    : 0;

                var newItems = await NotificationSvc.GetNewNotificationsSinceAsync(lastId);

                if (newItems.Count > 0)
                {
                    notifications ??= [];
                    notifications.AddRange(newItems);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

